 1→import { projectPartToView } from '../domain/viewProjection';
 2→
 3→export default function AssemblyBoundingBoxRenderer({ assembly, parts, view, zoom, isSelected, isEditMode }) {
 4→  // Filter to parts belonging to this assembly (non-dimension)
 5→  const asmParts = parts.filter((p) => p.assemblyId === assembly.id && p.type !== 'dimension');
 6→  if (asmParts.length === 0) return null;
 7→
 8→  // Compute bounding rect from projected parts
 9→  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
10→  for (const part of asmParts) {
11→    const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
12→    if (svgX < minX) minX = svgX;
13→    if (svgY < minY) minY = svgY;
14→    if (svgX + svgWidth > maxX) maxX = svgX + svgWidth;
15→    if (svgY + svgHeight > maxY) maxY = svgY + svgHeight;
16→  }
17→
18→  const pad = 8 / zoom;
19→  const x = minX - pad;
20→  const y = minY - pad;
21→  const w = maxX - minX + 2 * pad;
22→  const h = maxY - minY + 2 * pad;
23→
24→  const color = '#4682B4';
25→
26→  let strokeDash;
27→  let strokeWidth;
28→  if (isEditMode) {
29→    strokeDash = `${3 / zoom} ${3 / zoom}`;
30→    strokeWidth = 1 / zoom;
31→  } else if (isSelected) {
32→    strokeDash = undefined;
33→    strokeWidth = 2 / zoom;
34→  } else {
35→    strokeDash = `${6 / zoom} ${4 / zoom}`;
36→    strokeWidth = 1.5 / zoom;
37→  }
38→
39→  const fontSize = 12 / zoom;
40→  const labelY = y - 4 / zoom;
41→
42→  return (
43→    <g style={{ pointerEvents: 'none' }}>
44→      <rect
45→        x={x}
46→        y={y}
47→        width={w}
48→        height={h}
49→        fill="none"
50→        stroke={color}
51→        strokeWidth={strokeWidth}
52→        vectorEffect="non-scaling-stroke"
53→        strokeDasharray={strokeDash}
54→        opacity={isSelected || isEditMode ? 1 : 0.6}
55→      />
56→      <text
57→        x={x}
58→        y={labelY}
59→        fill={color}
60→        fontSize={fontSize}
61→        fontFamily="var(--font-ui)"
62→        fontWeight={isSelected ? 700 : 500}
63→        opacity={isSelected || isEditMode ? 1 : 0.7}
64→      >
65→        {assembly.name}
66→      </text>
67→    </g>
68→  );
69→}
