774→    }
775→
776→    return (
777→      <div className={styles.panel}>
778→        <div className={styles.header}>Properties</div>
779→        <div className={styles.empty}>No sheet selected</div>
780→      </div>
781→    );
782→  }
783→
784→  if (selectedType === 'object' && selectedId) {
785→    const object = (project.objects || []).find((entry) => entry.id === selectedId);
786→    if (object) {
787→      return <ObjectProperties key={object.id} object={object} project={project} dispatch={dispatch} editorDispatch={editorDispatch} />;
788→    }
789→  }
790→
791→  // Model mode: assembly selection
792→  if (selectedType === 'assembly' && selectedId) {
793→    const asm = project.assemblies.find((a) => a.id === selectedId);
794→    if (asm) {
795→      return (
796→        <AssemblyProperties key={asm.id} assembly={asm} project={project} dispatch={dispatch} />
797→      );
798→    }
799→  }
800→
801→  // Model mode properties
802→  const part = selectedId ? getPart(selectedId) : null;
803→
804→  if (!part) {
805→    return (
806→      <div className={styles.panel}>
807→        <div className={styles.header}>Properties</div>
808→        <div className={styles.empty}>Select an object, assembly, or part to view its properties</div>
809→      </div>
810→    );
811→  }
