813→  const handleUpdate = (changes) => {
814→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...changes } });
815→  };
816→
817→  const handlePositionUpdate = (posChanges) => {
818→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, position: { ...part.position, ...posChanges } } });
819→  };
820→
821→  const handleDuplicate = () => {
822→    dispatch({ type: 'PART_CLONE', partId: part.id });
