 19→function getAnchorAxis(anchor) {
 20→  switch (anchor) {
 21→    case 'top':
 22→    case 'bottom':
 23→      return 'z';
 24→    case 'left':
 25→    case 'right':
 26→      return 'x';
 27→    case 'front':
 28→    case 'back':
 29→      return 'y';
 30→    case 'center':
 31→      return null;
 32→    default:
 33→      return null;
 34→  }
 35→}
 36→
 37→function getAnchorExtentSize(part, anchor) {
 38→  const ext = getPartExtents(part);
 39→  switch (anchor) {
 40→    case 'top':
 41→    case 'bottom':
 42→      return ext.height;
 43→    case 'left':
 44→    case 'right':
 45→      return ext.width;
 46→    case 'front':
 47→    case 'back':
 48→      return ext.depth;
 49→    default:
 50→      return 0;
 51→  }
 52→}
