 54→export function resolveConstraints(constraints, parts) {
 55→  const positions = new Map();
 56→  const partsById = new Map(parts.map((p) => [p.id, p]));
 57→
 58→  for (const constraint of constraints) {
 59→    const source = partsById.get(constraint.sourcePartId);
 60→    const target = partsById.get(constraint.targetPartId);
 61→    if (!source || !target) continue;
 62→
 63→    // Use already-resolved position if available
 64→    const sourcePos = { ...source.position, ...(positions.get(source.id) || {}) };
 65→    const targetPos = { ...target.position, ...(positions.get(target.id) || {}) };
 66→
 67→    const workingSource = { ...source, position: sourcePos };
 68→    const workingTarget = { ...target, position: targetPos };
 69→
 70→    const newPos = { ...sourcePos };
 71→
 72→    switch (constraint.type) {
 73→      case 'attach_face': {
 74→        const axis = getAnchorAxis(constraint.targetAnchor);
 75→        if (!axis) break;
 76→        const targetAnchorVal = getAnchorPosition(workingTarget, constraint.targetAnchor);
 77→        const sourceExtent = getAnchorExtentSize(workingSource, constraint.sourceAnchor);
 78→
 79→        // Position source so its sourceAnchor face touches target's targetAnchor face
 80→        if (constraint.sourceAnchor === 'bottom' || constraint.sourceAnchor === 'left' || constraint.sourceAnchor === 'front') {
 81→          newPos[axis] = targetAnchorVal + constraint.offset;
 82→        } else {
 83→          newPos[axis] = targetAnchorVal - sourceExtent + constraint.offset;
 84→        }
 85→        break;
 86→      }
 87→
 88→      case 'flush_surface': {
 89→        const axis = getAnchorAxis(constraint.targetAnchor);
 90→        if (!axis) break;
 91→        const targetAnchorVal = getAnchorPosition(workingTarget, constraint.targetAnchor);
 92→        const sourceExtent = getAnchorExtentSize(workingSource, constraint.sourceAnchor);
 93→
 94→        if (constraint.sourceAnchor === 'bottom' || constraint.sourceAnchor === 'left' || constraint.sourceAnchor === 'front') {
 95→          newPos[axis] = targetAnchorVal;
 96→        } else {
 97→          newPos[axis] = targetAnchorVal - sourceExtent;
 98→        }
 99→        break;
100→      }

