  1→import { createContext, useContext, useReducer, useCallback } from 'react';
  2→import { createSketchProject } from '../domain/sketchModels';
  3→import { sanitizePartDimensions, sanitizePartPosition } from '../domain/validation';
  4→import { resolveConstraints } from '../domain/constraintResolver';
  5→import { updateBoundDimensionEndpoints } from '../domain/dimensionBinding';
  6→import { generateId } from '@/domain/ids';
  7→import { generateObjectFromTemplate } from '../domain/objectGenerator';
  8→import { normalizeSketchObjects } from '../domain/objectModels';
  9→
 10→const SketchContext = createContext(null);
 11→const HISTORY_LIMIT = 80;
 12→
 13→function snapshotSketch(sketchProject) {
 14→  return JSON.stringify(sketchProject);
 15→}
 16→
 17→function applyUpdate(state, nextProject, recordHistory = true) {
 18→  const normalizedProject = normalizeSketchObjects(nextProject);
 19→  const nextSnapshot = snapshotSketch(normalizedProject);
 20→  const history = recordHistory
 21→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 22→    : state.history;
 23→
 24→  return {
 25→    ...state,
 26→    history,
 27→    future: recordHistory ? [] : state.future,
 28→    project: normalizedProject,
 29→    isDirty: nextSnapshot !== state.savedSnapshot,
 30→  };
 31→}
 32→
 33→function mergePart(existing, updates) {
 34→  const merged = { ...existing, ...updates };
 35→  if (updates.position) {
 36→    merged.position = { ...existing.position, ...updates.position };
 37→  }
 38→  if (updates.rotation) {
 39→    merged.rotation = { ...existing.rotation, ...updates.rotation };
 40→  }
 41→  return merged;
 42→}
 43→
 44→function sanitizePart(part) {
 45→  if (part.type === 'dimension') return part;
 46→  return sanitizePartPosition(sanitizePartDimensions(part));
 47→}
 48→
 49→function applyConstraints(project) {
 50→  const constraints = project.constraints || [];
 51→  if (constraints.length === 0) return project;
 52→
 53→  const resolved = resolveConstraints(constraints, project.parts);
 54→  if (resolved.size === 0) return project;
 55→
 56→  return {
 57→    ...project,
 58→    parts: project.parts.map((part) => {
 59→      const newPos = resolved.get(part.id);
 60→      return newPos ? { ...part, position: newPos } : part;
 61→    }),
 62→  };
 63→}
 64→
 65→function updateBoundDimensions(project, updatedPartId) {
 66→  const updatedPart = project.parts.find((part) => part.id === updatedPartId);
 67→  if (!updatedPart) return project;
 68→
 69→  let changed = false;
 70→  const newParts = project.parts.map((part) => {
 71→    if (part.type === 'dimension' && part.boundPartId === updatedPartId) {
 72→      changed = true;
 73→      return updateBoundDimensionEndpoints(part, updatedPart);
 74→    }
 75→    return part;
 76→  });
 77→
 78→  return changed ? { ...project, parts: newParts } : project;
 79→}
 80→
 81→function clonePart(part, idMap) {
 82→  const newId = generateId('part');
 83→  idMap.set(part.id, newId);
 84→  return {
 85→    ...part,
 86→    id: newId,
 87→    name: `${part.name} (copy)`,
 88→    objectId: part.objectId || null,
 89→    source: 'manual',
 90→    locked: false,
 91→    position: {
 92→      ...part.position,
 93→      x: part.position.x + 50,
 94→      y: part.position.y + 50,
 95→    },
 96→  };
 97→}
 98→
 99→function getManagedObject(project, objectId) {
100→  if (!objectId) return null;
101→  return (project.objects || []).find((object) => object.id === objectId) || null;
102→}
103→
104→function getManagedObjectForPart(project, partId) {
105→  const part = project.parts.find((entry) => entry.id === partId);
106→  const object = part?.objectId ? getManagedObject(project, part.objectId) : null;
107→  return object?.editingPolicy === 'parametric' ? object : null;
108→}
109→
110→function getManagedObjectForAssembly(project, assemblyId) {
111→  const assembly = project.assemblies.find((entry) => entry.id === assemblyId);
112→  const object = assembly?.objectId ? getManagedObject(project, assembly.objectId) : null;
113→  return object?.editingPolicy === 'parametric' ? object : null;
114→}
115→
116→function removePartsAndAssemblies(project, { partIds, assemblyIds }) {
117→  const idsToRemove = new Set(partIds);
118→  const assemblyIdSet = new Set(assemblyIds);
119→
120→  const childIds = new Set(
121→    project.parts.filter((part) => idsToRemove.has(part.parentId)).map((part) => part.id)
122→  );
123→  for (const childId of childIds) idsToRemove.add(childId);
124→
125→  const constraints = (project.constraints || []).filter(
126→    (constraint) => !idsToRemove.has(constraint.sourcePartId) && !idsToRemove.has(constraint.targetPartId)
127→  );
128→
129→  return {
130→    ...project,
131→    parts: project.parts
132→      .filter((part) => !idsToRemove.has(part.id))
133→      .map((part) => {
134→        if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
135→          return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
136→        }
137→        return part;
138→      }),
139→    assemblies: project.assemblies.filter((assembly) => !assemblyIdSet.has(assembly.id)),
140→    constraints,
141→  };
142→}
143→
144→function removeObjectArtifacts(project, objectId) {
145→  const partIds = project.parts
146→    .filter((part) => part.objectId === objectId)
147→    .map((part) => part.id);
148→  const assemblyIds = project.assemblies
149→    .filter((assembly) => assembly.objectId === objectId)
150→    .map((assembly) => assembly.id);
151→
152→  return removePartsAndAssemblies(project, { partIds, assemblyIds });
153→}
154→
155→function retargetManagedViewports(sheets, objectId, oldAssemblyIds = []) {
156→  const oldAssemblyIdSet = new Set(oldAssemblyIds);
157→
158→  return (sheets || []).map((sheet) => ({
159→    ...sheet,
160→    viewports: (sheet.viewports || []).map((viewport) => {
161→      if (viewport.sourceRefId !== objectId && !oldAssemblyIdSet.has(viewport.sourceRefId)) {
162→        return viewport;
163→      }
164→
165→      if (viewport.sourceView === 'sketch_assembly_top') {
166→        return { ...viewport, sourceView: 'sketch_object_top', sourceRefId: objectId };
167→      }
168→      if (viewport.sourceView === 'sketch_assembly_front') {
169→        return { ...viewport, sourceView: 'sketch_object_front', sourceRefId: objectId };
170→      }
171→      if (viewport.sourceView === 'sketch_assembly_side') {
172→        return { ...viewport, sourceView: 'sketch_object_side', sourceRefId: objectId };
173→      }
174→      if (viewport.sourceView === 'sketch_part_list') {
175→        return { ...viewport, sourceRefId: objectId, sourceObjectId: objectId };
176→      }
177→
178→      return viewport;
179→    }),
180→  }));
181→}
182→
183→function detachManagedObject(project, objectId) {
184→  return {
185→    ...project,
186→    objects: (project.objects || []).map((object) => (
187→      object.id === objectId
188→        ? {
189→            ...object,
190→            source: 'custom',
191→            editingPolicy: 'manual',
192→            templateType: null,
193→            templateParams: null,
194→            summary: object.summary || 'Detached custom object',
195→            updatedAt: new Date().toISOString(),
196→          }
197→        : object
198→    )),
199→    assemblies: project.assemblies.map((assembly) => (
200→      assembly.objectId === objectId
201→        ? {
202→            ...assembly,
203→            source: 'manual',
204→            role: assembly.role || null,
205→          }
206→        : assembly
207→    )),
208→    parts: project.parts.map((part) => (
209→      part.objectId === objectId
210→        ? {
211→          ...part,
212→            source: 'manual',
213→            locked: false,
214→          }
215→        : part
216→    )),
217→  };
218→}
219→
220→function addGeneratedObject(project, generated) {
221→  return {
222→    ...project,
223→    objects: [...(project.objects || []), generated.object],
224→    assemblies: [...project.assemblies, ...generated.assemblies],
225→    parts: [...project.parts, ...generated.parts.map(sanitizePart)],
226→  };
227→}
228→
229→function rebuildManagedObject(project, object, params) {
230→  const oldAssemblyIds = project.assemblies
231→    .filter((assembly) => assembly.objectId === object.id)
232→    .map((assembly) => assembly.id);
233→
234→  const strippedProject = removeObjectArtifacts(project, object.id);
235→  const generated = generateObjectFromTemplate(object.templateType, params, {
236→    objectId: object.id,
237→    name: object.name,
238→    origin: object.origin,
239→  });
240→
241→  const nextProject = addGeneratedObject({
242→    ...strippedProject,
243→    objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
244→    sheets: retargetManagedViewports(strippedProject.sheets, object.id, oldAssemblyIds),
245→  }, generated);
246→
247→  return nextProject;
248→}
249→
250→function sketchReducer(state, action) {
251→  switch (action.type) {
252→    case 'SKETCH_NEW': {
253→      const newProject = action.project || createSketchProject();
254→      return {
255→        project: newProject,
256→        isDirty: false,
257→        savedSnapshot: snapshotSketch(newProject),
258→        history: [],
259→        future: [],
260→      };
261→    }
262→
263→    case 'SKETCH_LOAD': {
264→      const loaded = normalizeSketchObjects(action.project);
265→      return {
266→        project: loaded,
267→        isDirty: false,
268→        savedSnapshot: snapshotSketch(loaded),
269→        history: [],
270→        future: [],
271→      };
272→    }
273→
274→    case 'PART_ADD': {
275→      const part = sanitizePart(action.part);
276→      const assembly = part.assemblyId
277→        ? state.project.assemblies.find((entry) => entry.id === part.assemblyId)
278→        : null;
279→      const nextPart = assembly && assembly.objectId
280→        ? { ...part, objectId: assembly.objectId }
281→        : part;
282→      let nextProject = {
283→        ...state.project,
284→        updatedAt: new Date().toISOString(),
285→        parts: [...state.project.parts, nextPart],
286→      };
287→      nextProject = applyConstraints(nextProject);
288→      return applyUpdate(state, nextProject);
289→    }
290→
291→    case 'PART_UPDATE': {
292→      const managedObject = getManagedObjectForPart(state.project, action.part.id);
293→      if (managedObject && !action.allowManagedUpdate) return state;
294→
295→      let nextProject = {
296→        ...state.project,
297→        updatedAt: new Date().toISOString(),
298→        parts: state.project.parts.map((part) => {
299→          if (part.id !== action.part.id) return part;
300→          const merged = mergePart(part, action.part);
301→          return merged.type === 'dimension' ? merged : sanitizePart(merged);
302→        }),
303→      };
304→      nextProject = applyConstraints(nextProject);
305→      nextProject = updateBoundDimensions(nextProject, action.part.id);
306→      return applyUpdate(state, nextProject);
307→    }
308→
309→    case 'PART_DELETE': {
310→      const managedObject = getManagedObjectForPart(state.project, action.partId);
311→      if (managedObject) return state;
312→
313→      const partId = action.partId;
314→      const childIds = new Set(
315→        state.project.parts.filter((part) => part.parentId === partId).map((part) => part.id)
316→      );
317→      const idsToRemove = new Set([partId, ...childIds]);
318→
319→      const constraints = (state.project.constraints || []).filter(
320→        (constraint) => !idsToRemove.has(constraint.sourcePartId) && !idsToRemove.has(constraint.targetPartId)
321→      );
322→
323→      return applyUpdate(state, {
324→        ...state.project,
325→        updatedAt: new Date().toISOString(),
326→        parts: state.project.parts
327→          .filter((part) => !idsToRemove.has(part.id))
328→          .map((part) => {
329→            if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
330→              return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
331→            }
332→            return part;
333→          }),
334→        assemblies: state.project.assemblies.map((assembly) => ({
335→          ...assembly,
336→          partIds: assembly.partIds.filter((id) => !idsToRemove.has(id)),
337→        })),
338→        constraints,
339→      });
340→    }
341→
342→    case 'PART_CLONE': {
343→      const managedObject = getManagedObjectForPart(state.project, action.partId);
344→      if (managedObject) return state;
345→
346→      const part = state.project.parts.find((entry) => entry.id === action.partId);
347→      if (!part) return state;
348→
349→      const idMap = new Map();
350→      const cloned = clonePart(part, idMap);
351→      const children = state.project.parts.filter((entry) => entry.parentId === action.partId);
352→      const clonedChildren = children.map((child) => {
353→        const clonedChild = clonePart(child, idMap);
354→        clonedChild.parentId = cloned.id;
355→        return clonedChild;
356→      });
357→
358→      const newParts = [cloned, ...clonedChildren];
359→      let assemblies = state.project.assemblies;
360→      if (part.assemblyId) {
361→        assemblies = assemblies.map((assembly) => {
362→          if (assembly.id === part.assemblyId) {
363→            return {
364→              ...assembly,
365→              partIds: [...assembly.partIds, ...newParts.map((entry) => entry.id)],
366→            };
367→          }
368→          return assembly;
369→        });
370→        for (const nextPart of newParts) {
371→          nextPart.assemblyId = part.assemblyId;
372→        }
373→      }
374→
375→      return applyUpdate(state, {
376→        ...state.project,
377→        updatedAt: new Date().toISOString(),
378→        parts: [...state.project.parts, ...newParts],
379→        assemblies,
380→      });
381→    }
382→
383→    case 'ASSEMBLY_ADD':
384→      return applyUpdate(state, {
385→        ...state.project,
386→        updatedAt: new Date().toISOString(),
387→        assemblies: [...state.project.assemblies, { ...action.assembly, source: action.assembly.source || 'manual' }],
388→      });
389→
390→    case 'ASSEMBLY_UPDATE': {
391→      const managedObject = getManagedObjectForAssembly(state.project, action.assembly.id);
392→      if (managedObject) return state;
393→
394→      return applyUpdate(state, {
395→        ...state.project,
396→        updatedAt: new Date().toISOString(),
397→        assemblies: state.project.assemblies.map((assembly) => (
398→          assembly.id === action.assembly.id ? { ...assembly, ...action.assembly } : assembly
399→        )),
400→      });
401→    }
402→
403→    case 'ASSEMBLY_DELETE': {
404→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
405→      if (managedObject) return state;
406→
407→      const assemblyId = action.assemblyId;
408→      return applyUpdate(state, {
409→        ...state.project,
410→        updatedAt: new Date().toISOString(),
411→        assemblies: state.project.assemblies.filter((assembly) => assembly.id !== assemblyId),
412→        parts: state.project.parts.map((part) => (
413→          part.assemblyId === assemblyId ? { ...part, assemblyId: null } : part
414→        )),
415→      });
416→    }
417→
418→    case 'ASSEMBLY_MOVE': {
419→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
420→      if (managedObject) {
421→        return sketchReducer(state, {
422→          type: 'OBJECT_MOVE',
423→          objectId: managedObject.id,
424→          delta: action.delta,
425→        });
426→      }
427→
428→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
429→      if (!assembly) return state;
430→
431→      const partIdSet = new Set(assembly.partIds);
432→      let nextProject = {
433→        ...state.project,
434→        updatedAt: new Date().toISOString(),
435→        parts: state.project.parts.map((part) => {
436→          if (!partIdSet.has(part.id) || part.type === 'dimension') return part;
437→          const moved = {
438→            ...part,
439→            position: {
440→              x: part.position.x + (action.delta.dx || 0),
441→              y: part.position.y + (action.delta.dy || 0),
442→              z: part.position.z + (action.delta.dz || 0),
443→            },
444→          };
445→          return sanitizePart(moved);
446→        }),
447→      };
448→      nextProject = applyConstraints(nextProject);
449→      for (const partId of partIdSet) {
450→        nextProject = updateBoundDimensions(nextProject, partId);
451→      }
452→      return applyUpdate(state, nextProject);
453→    }
454→
455→    case 'ASSEMBLY_DELETE_WITH_PARTS': {
456→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
457→      if (managedObject) {
458→        return sketchReducer(state, {
459→          type: 'OBJECT_DELETE',
460→          objectId: managedObject.id,
461→        });
462→      }
463→
464→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
465→      if (!assembly) return state;
466→
467→      return applyUpdate(state, {
468→        ...removePartsAndAssemblies(state.project, {
469→          partIds: assembly.partIds,
470→          assemblyIds: [assembly.id],
471→        }),
472→        updatedAt: new Date().toISOString(),
473→      });
474→    }
475→
476→    case 'ASSEMBLY_ADD_PART': {
477→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
478→      if (managedObject) return state;
479→
480→       const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
481→
482→      return applyUpdate(state, {
483→        ...state.project,
484→        updatedAt: new Date().toISOString(),
485→        assemblies: state.project.assemblies.map((assembly) => (
486→          assembly.id === action.assemblyId && !assembly.partIds.includes(action.partId)
487→            ? { ...assembly, partIds: [...assembly.partIds, action.partId] }
488→            : assembly
489→        )),
490→        parts: state.project.parts.map((part) => (
491→          part.id === action.partId
492→            ? { ...part, assemblyId: action.assemblyId, objectId: assembly?.objectId || part.objectId || null }
493→            : part
494→        )),
495→      });
496→    }
497→
498→    case 'ASSEMBLY_REMOVE_PART': {
499→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
500→      if (managedObject) return state;
501→
502→      return applyUpdate(state, {
503→        ...state.project,
504→        updatedAt: new Date().toISOString(),
505→        assemblies: state.project.assemblies.map((assembly) => (
506→          assembly.id === action.assemblyId
507→            ? { ...assembly, partIds: assembly.partIds.filter((id) => id !== action.partId) }
508→            : assembly
509→        )),
510→        parts: state.project.parts.map((part) => (
511→          part.id === action.partId && part.assemblyId === action.assemblyId
512→            ? { ...part, assemblyId: null }
513→            : part
514→        )),
515→      });
516→    }
517→
518→    case 'ASSEMBLY_CLONE': {
519→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
520→      if (managedObject) return state;
521→
522→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
523→      if (!assembly) return state;
524→
525→      const idMap = new Map();
526→      const newAssemblyId = generateId('asm');
527→      const newAssembly = {
528→        ...assembly,
529→        id: newAssemblyId,
530→        name: `${assembly.name} (copy)`,
531→        partIds: [],
532→        objectId: assembly.objectId || null,
533→        source: 'manual',
534→      };
535→
536→      const assemblyParts = state.project.parts.filter((part) => part.assemblyId === action.assemblyId);
537→      const clonedParts = [];
538→
539→      for (const part of assemblyParts) {
540→        const cloned = clonePart(part, idMap);
541→        cloned.assemblyId = newAssemblyId;
542→        clonedParts.push(cloned);
543→      }
544→
545→      for (const clonedPart of clonedParts) {
546→        if (clonedPart.parentId && idMap.has(clonedPart.parentId)) {
547→          clonedPart.parentId = idMap.get(clonedPart.parentId);
548→        }
549→      }
550→
551→      newAssembly.partIds = clonedParts.map((part) => part.id);
552→
553→      return applyUpdate(state, {
554→        ...state.project,
555→        updatedAt: new Date().toISOString(),
556→        parts: [...state.project.parts, ...clonedParts],
557→        assemblies: [...state.project.assemblies, newAssembly],
558→      });
559→    }
560→
561→    case 'OBJECT_UPDATE':
562→      return applyUpdate(state, {
563→        ...state.project,
564→        updatedAt: new Date().toISOString(),
565→        objects: (state.project.objects || []).map((object) => (
566→          object.id === action.object.id
567→            ? {
568→                ...object,
569→                ...action.object,
570→                templateParams: action.object.templateParams
571→                  ? { ...action.object.templateParams }
572→                  : object.templateParams,
573→                dimensions: action.object.dimensions
574→                  ? { ...action.object.dimensions }
575→                  : object.dimensions,
576→                updatedAt: new Date().toISOString(),
577→              }
578→            : object
579→        )),
580→      });
581→
582→    case 'OBJECT_DELETE': {
583→      const object = getManagedObject(state.project, action.objectId);
584→      if (!object) return state;
585→
586→      const strippedProject = removeObjectArtifacts(state.project, object.id);
587→      return applyUpdate(state, {
588→        ...strippedProject,
589→        updatedAt: new Date().toISOString(),
590→        objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
591→      });
592→    }
593→
594→    case 'OBJECT_MOVE': {
595→      const object = getManagedObject(state.project, action.objectId);
596→      if (!object) return state;
597→
598→      const partIds = new Set(
599→        state.project.parts.filter((part) => part.objectId === object.id).map((part) => part.id)
600→      );
601→
602→      let nextProject = {
603→        ...state.project,
604→        updatedAt: new Date().toISOString(),
605→        objects: state.project.objects.map((entry) => (
606→          entry.id === object.id
607→            ? {
608→                ...entry,
609→                origin: {
610→                  x: entry.origin.x + (action.delta.dx || 0),
611→                  y: entry.origin.y + (action.delta.dy || 0),
612→                  z: entry.origin.z + (action.delta.dz || 0),
613→                },
614→                updatedAt: new Date().toISOString(),
615→              }
616→            : entry
617→        )),
618→        parts: state.project.parts.map((part) => {
619→          if (!partIds.has(part.id) || part.type === 'dimension') return part;
620→          return sanitizePart({
621→            ...part,
622→            position: {
623→              x: part.position.x + (action.delta.dx || 0),
624→              y: part.position.y + (action.delta.dy || 0),
625→              z: part.position.z + (action.delta.dz || 0),
626→            },
627→          });
628→        }),
629→      };
630→      nextProject = applyConstraints(nextProject);
631→      for (const partId of partIds) {
632→        nextProject = updateBoundDimensions(nextProject, partId);
633→      }
634→      return applyUpdate(state, nextProject);
635→    }
636→
637→    case 'OBJECT_DETACH': {
638→      const object = getManagedObject(state.project, action.objectId);
639→      if (!object) return state;
640→      return applyUpdate(state, {
641→        ...detachManagedObject(state.project, object.id),
642→        updatedAt: new Date().toISOString(),
643→      });
644→    }
645→
646→    case 'CONSTRAINT_ADD': {
647→      const constraints = [...(state.project.constraints || []), action.constraint];
648→      let nextProject = {
649→        ...state.project,
650→        updatedAt: new Date().toISOString(),
651→        constraints,
652→      };
653→      nextProject = applyConstraints(nextProject);
654→      return applyUpdate(state, nextProject);
655→    }
656→
657→    case 'CONSTRAINT_UPDATE': {
658→      const constraints = (state.project.constraints || []).map((constraint) => (
659→        constraint.id === action.constraint.id ? { ...constraint, ...action.constraint } : constraint
660→      ));
661→      let nextProject = {
662→        ...state.project,
663→        updatedAt: new Date().toISOString(),
664→        constraints,
665→      };
666→      nextProject = applyConstraints(nextProject);
667→      return applyUpdate(state, nextProject);
668→    }
669→
670→    case 'CONSTRAINT_DELETE': {
671→      const constraints = (state.project.constraints || []).filter(
672→        (constraint) => constraint.id !== action.constraintId
673→      );
674→      return applyUpdate(state, {
675→        ...state.project,
676→        updatedAt: new Date().toISOString(),
677→        constraints,
678→      });
679→    }
680→
681→    case 'ANNOTATION_ADD':
682→      return applyUpdate(state, {
683→        ...state.project,
684→        updatedAt: new Date().toISOString(),
685→        annotations: [...(state.project.annotations || []), action.annotation],
686→      });
687→
688→    case 'ANNOTATION_UPDATE':
689→      return applyUpdate(state, {
