 34→        },
 35→      },
 36→      {
 37→        type: 'panel',
 38→        role: 'right_side',
 39→        name: 'Right Side',
 40→        props: {
 41→          width: panelThickness,
 42→          depth,
 43→          thickness: height,
 44→          material: 'plywood',
 45→          position: { x: width - panelThickness, y: 0, z: 0 },
 46→        },
 47→      },
 48→      {
 49→        type: 'panel',
 50→        role: 'bottom',
 51→        name: 'Bottom',
