677→export default function SketchPropertiesPanel() {
678→  const { getPart, dispatch, project } = useSketch();
679→  const { selectedId, selectedType, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
680→
681→  const isSheetMode = workspaceMode === 'sheet';
682→  const activeSheet = isSheetMode
683→    ? (project.sheets || []).find((s) => s.id === activeSheetId)
684→    : null;
685→
686→  // Sheet mode properties
687→  if (isSheetMode) {
688→    if (selectedType === 'sheetViewport' && selectedId && activeSheet) {
689→      const viewport = (activeSheet.viewports || []).find((vp) => vp.id === selectedId);
690→      if (viewport) {
691→        return (
692→          <div className={styles.panel}>
693→            <div className={styles.header}>Viewport Properties</div>
694→            <div className={styles.content}>
695→              <SheetViewportProperties
696→                viewport={viewport}
697→                sheet={activeSheet}
698→                project={project}
699→                dispatch={dispatch}
700→              />
701→            </div>
702→          </div>
703→        );
704→      }
705→    }
706→
707→    if (activeSheet) {
708→      const handleGenerateObjectSheet = (objectId) => {
709→        const sheet = generateObjectSheet(project, objectId);
710→        dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
711→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
712→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
713→      };
714→
715→      const handleGenerateAssemblySheet = (assemblyId) => {
716→        const sheet = generateAssemblySheet(project, assemblyId);
717→        dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
718→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
719→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
720→      };
721→
722→      const handleExportPdf = async () => {
723→        try {
724→          await exportActiveSheetAsPdf(activeSheet.title || 'sketch-sheet', activeSheet.paperSize);
725→        } catch (err) {
