743→
744→            <div className={styles.fieldGroup}>
745→              <span className={styles.groupTitle}>Actions</span>
746→              {(project.objects || []).map((object) => (
747→                <button
748→                  key={object.id}
749→                  className={styles.duplicateBtn}
750→                  onClick={() => handleGenerateObjectSheet(object.id)}
751→                >
