762→                </button>
763→              ))}
764→              <button className={styles.duplicateBtn} onClick={handleExportPdf}>
765→                Export PDF
766→              </button>
767→              <button className={styles.duplicateBtn} onClick={handleExportPng}>
768→                Export PNG
769→              </button>
770→            </div>
771→          </div>
772→        </div>
