774→    }
775→
776→    return (
777→      <div className={styles.panel}>
778→        <div className={styles.header}>Properties</div>
779→        <div className={styles.empty}>No sheet selected</div>
780→      </div>
781→    );
782→  }
783→
784→  if (selectedType === 'object' && selectedId) {
785→    const object = (project.objects || []).find((entry) => entry.id === selectedId);
786→    if (object) {
787→      return <ObjectProperties key={object.id} object={object} project={project} dispatch={dispatch} editorDispatch={editorDispatch} />;
788→    }
